# Python MySQL Data Import Script with Security Controls

import mysql.connector
from mysql.connector import Error
import os
import re
from pathlib import Path
import hashlib
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class SecureDataImporter:
    def __init__(self, host, database, user, password, allowed_directories=None):
        self.host = host
        self.database = database
        self.user = user
        self.password = password
        self.connection = None
        self.allowed_directories = allowed_directories or []
        self.allowed_extensions = ['.csv', '.txt', '.tsv']
        
    def connect(self):
        try:
            self.connection = mysql.connector.connect(
                host=self.host,
                database=self.database,
                user=self.user,
                password=self.password,
                allow_local_infile=True
            )
            if self.connection.is_connected():
                logger.info("Successfully connected to MySQL database")
                return True
        except Error as e:
            logger.error(f"Error connecting to MySQL: {e}")
            return False
    
    def disconnect(self):
        if self.connection and self.connection.is_connected():
            self.connection.close()
            logger.info("MySQL connection closed")
    
    def validate_file_path(self, file_path):
        try:
            path = Path(file_path).resolve()
            
            if not path.exists():
                logger.error(f"File does not exist: {file_path}")
                return False
            
            if not path.is_file():
                logger.error(f"Path is not a file: {file_path}")
                return False
            
            if path.suffix.lower() not in self.allowed_extensions:
                logger.error(f"File extension not allowed: {path.suffix}")
                return False
            
            if self.allowed_directories:
                is_in_allowed_dir = False
                for allowed_dir in self.allowed_directories:
                    try:
                        allowed_path = Path(allowed_dir).resolve()
                        if allowed_path in path.parents or path.parent == allowed_path:
                            is_in_allowed_dir = True
                            break
                    except Exception as e:
                        logger.error(f"Error checking allowed directory {allowed_dir}: {e}")
                        continue
                
                if not is_in_allowed_dir:
                    logger.error(f"File is not in allowed directories: {file_path}")
                    return False
            
            if os.path.getsize(path) > 1024 * 1024 * 1024:  # 1GB limit
                logger.error(f"File size exceeds limit: {file_path}")
                return False
            
            return True
            
        except Exception as e:
            logger.error(f"Error validating file path: {e}")
            return False
    
    def validate_table_name(self, table_name):
        if not re.match(r'^[a-zA-Z0-9_]+$', table_name):
            logger.error(f"Invalid table name: {table_name}")
            return False
        return True
    
    def sanitize_identifier(self, identifier):
        return '`' + identifier.replace('`', '``') + '`'
    
    def table_exists(self, table_name):
        try:
            cursor = self.connection.cursor()
            cursor.execute(f"SHOW TABLES LIKE %s", (table_name,))
            result = cursor.fetchone()
            cursor.close()
            return result is not None
        except Error as e:
            logger.error(f"Error checking table existence: {e}")
            return False
    
    def get_file_checksum(self, file_path):
        sha256_hash = hashlib.sha256()
        with open(file_path, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    
    def load_data_infile(self, file_path, table_name, fields_terminated_by=',', 
                         lines_terminated_by='\\n', ignore_lines=1, 
                         enclosed_by='"', escaped_by='\\\\'):
        
        if not self.validate_file_path(file_path):
            logger.error("File path validation failed")
            return False
        
        if not self.validate_table_name(table_name):
            logger.error("Table name validation failed")
            return False
        
        if not self.table_exists(table_name):
            logger.error(f"Table does not exist: {table_name}")
            return False
        
        try:
            file_path_resolved = str(Path(file_path).resolve())
            file_checksum = self.get_file_checksum(file_path_resolved)
            logger.info(f"File checksum (SHA256): {file_checksum}")
            
            safe_table_name = self.sanitize_identifier(table_name)
            
            fields_terminated_by = fields_terminated_by.replace("'", "\\'")
            lines_terminated_by = lines_terminated_by.replace("'", "\\'")
            enclosed_by = enclosed_by.replace("'", "\\'") if enclosed_by else ''
            escaped_by = escaped_by.replace("'", "\\'")
            
            enclosed_clause = f"ENCLOSED BY '{enclosed_by}'" if enclosed_by else ""
            
            query = f"""
                LOAD DATA LOCAL INFILE '{file_path_resolved}'
                INTO TABLE {safe_table_name}
                FIELDS TERMINATED BY '{fields_terminated_by}'
                {enclosed_clause}
                ESCAPED BY '{escaped_by}'
                LINES TERMINATED BY '{lines_terminated_by}'
                IGNORE {ignore_lines} LINES
            """
            
            cursor = self.connection.cursor()
            
            cursor.execute(f"SELECT COUNT(*) FROM {safe_table_name}")
            count_before = cursor.fetchone()[0]
            
            logger.info(f"Executing LOAD DATA INFILE for file: {file_path_resolved}")
            cursor.execute(query)
            self.connection.commit()
            
            cursor.execute(f"SELECT COUNT(*) FROM {safe_table_name}")
            count_after = cursor.fetchone()[0]
            
            rows_imported = count_after - count_before
            warnings = cursor.fetchwarnings()
            
            cursor.close()
            
            logger.info(f"Successfully imported {rows_imported} rows into {table_name}")
            if warnings:
                logger.warning(f"Import warnings: {warnings}")
            
            return True
            
        except Error as e:
            logger.error(f"Error during LOAD DATA INFILE: {e}")
            if self.connection:
                self.connection.rollback()
            return False
        except Exception as e:
            logger.error(f"Unexpected error: {e}")
            if self.connection:
                self.connection.rollback()
            return False


